// PATCH: Cover duplicate clustering when handled split/group rows share a cluster.

func TestBuildDuplicateClustersFiltersHandledMembersOnly(t *testing.T) {
	splitParent := duplicateTestTx("split-parent", "Coffee", 12.00, "2026-05-01")
	splitParent.IsSplitParent = true
	txs := []localTransaction{
		splitParent,
		duplicateTestTx("dup-a", "Coffee", 12.10, "2026-05-01"),
		duplicateTestTx("dup-b", "Coffee", 12.20, "2026-05-02"),
	}

	results := buildDuplicateClusters(txs, 3, 1.00, 2)
	if len(results) != 1 {
		t.Fatalf("results = %+v, want one duplicate cluster", results)
	}
	got := results[0]
	if got.ClusterSize != 2 {
		t.Fatalf("ClusterSize = %d, want 2", got.ClusterSize)
	}
	gotIDs := []string{got.Transactions[0].ID, got.Transactions[1].ID}
	wantIDs := []string{"dup-a", "dup-b"}
	for i := range wantIDs {
		if gotIDs[i] != wantIDs[i] {
			t.Fatalf("transaction IDs = %v, want %v", gotIDs, wantIDs)
		}
	}
}

func duplicateTestTx(id, payee string, amount float64, dateString string) localTransaction {
	date, err := time.Parse("2006-01-02", dateString)
	if err != nil {
		panic(err)
	}
	return localTransaction{
		ID:              id,
		Payee:           payee,
		PayeeNormalized: normalizeLocalPayee(payee),
		Amount:          amount,
		Date:            date,
		DateString:      dateString,
	}
}
